<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/bootstrap.php';
try{$pdo=connectDatabase();$admin=requireAdmin($pdo);}catch(Throwable $error){error_log($error->getMessage());exit('Database connection failed.');}
$search=trim((string)($_GET['search']??''));$params=[];$where="WHERE a.status='completed'";
if($search!==''){$where.=' AND (u.public_id LIKE :search_public_id OR u.full_name LIKE :search_name OR u.phone LIKE :search_phone OR a.car_license LIKE :search_car OR m.name LIKE :search_mechanic)';$searchValue='%'.$search.'%';$params=['search_public_id'=>$searchValue,'search_name'=>$searchValue,'search_phone'=>$searchValue,'search_car'=>$searchValue,'search_mechanic'=>$searchValue];}
$sql="SELECT a.*,u.public_id,u.full_name AS customer_name,u.phone AS customer_phone,m.name AS mechanic_name FROM appointments a INNER JOIN users u ON u.id=a.user_id INNER JOIN mechanics m ON m.id=a.mechanic_id {$where} ORDER BY a.completed_at DESC,a.appointment_date DESC";$stmt=$pdo->prepare($sql);$stmt->execute($params);$appointments=$stmt->fetchAll();
?>
