<section class="history-overview glass-card"><div class="history-overview-icon">↻</div><div><small>Completed appointments</small><strong><?= count($appointments) ?></strong><span><?= $search!==''?'Matching your search':'Available in history' ?></span></div><form class="history-search-form" method="get"><label for="historySearch">Find a completed appointment</label><div><input id="historySearch" name="search" type="search" value="<?= e($search) ?>" placeholder="Customer, phone, car or mechanic"><button class="btn btn-primary" type="submit">Search</button></div></form><?php if($search!==''): ?><a class="history-clear" href="<?= e(appUrl('admin/history.php')) ?>">Clear search</a><?php endif; ?></section>
<article class="history-table-card strong-card"><div class="table-heading"><div><p class="section-kicker">Completed only</p><h2>History Records</h2></div><span><?= count($appointments) ?> result<?= count($appointments)===1?'':'s' ?></span></div><div class="table-scroll"><table class="secure-admin-table"><thead><tr><th>Customer</th><th>Contact</th><th>Vehicle</th><th>Appointment</th><th>Mechanic</th><th>Completed</th></tr></thead><tbody><?php foreach($appointments as $a): ?><tr><td><strong><?= e($a['customer_name']) ?></strong><small class="table-subtext"><?= e($a['public_id']) ?></small></td><td><?= e($a['customer_phone']) ?></td><td><strong><?= e($a['car_license']) ?></strong><small class="table-subtext"><?= e($a['car_engine']) ?></small></td><td><strong><?= e(date('d M Y',strtotime($a['appointment_date']))) ?></strong><small class="table-subtext"><?= $a['appointment_time']!==null?e(date('h:i A',strtotime($a['appointment_time']))):'Time not assigned' ?></small></td><td><span class="mechanic-name-cell"><i><?= e(initials($a['mechanic_name'])) ?></i><?= e($a['mechanic_name']) ?></span></td><td><span class="completed-stamp">✓ <?= $a['completed_at']!==null?e(date('d M Y',strtotime($a['completed_at']))):'Completed' ?></span></td></tr><?php endforeach; ?><?php if(!$appointments): ?><tr><td class="empty-table" colspan="6"><strong>No completed appointments found.</strong><small>Completed appointments will appear here.</small></td></tr><?php endif; ?></tbody></table></div></article></main><script src="<?= e(appUrl('assets/js/admin.js')) ?>"></script></body></html>
